          <div style={{ background: "#0d0d0d", border: "1px solid #1a1a1a", borderRadius: 14, padding: "10px 6px", maxHeight: 520, overflowY: "auto" }}><div style={{ padding: "0 8px 6px", fontSize: 9, fontWeight: 600, color: "#555", letterSpacing: "0.05em" }}>{{"tg_splash":"ТГ СПЛЭШ","auth":"АВТОРИЗАЦИЯ","email_confirm":"EMAIL ПОДТВЕРЖДЕНИЕ","password_reset":"СБРОС ПАРОЛЯ","onboarding":"ОНБОРДИНГ","catalog":"КАТАЛОГ","profile":"ПРОФИЛЬ","settings":"НАСТРОЙКИ","faq":"FAQ","language":"ЯЗЫК","player":"ПЛЕЕР"}[activeScreen]} ({elements.length})</div>{elements.map(name => (<button key={name} onClick={() => setSelected(selected === name ? null : name)} style={{ display: "block", width: "100%", textAlign: "left", fontSize: 11, color: selected === name ? WHITE : GREY, background: selected === name ? TURF : "transparent", border: "none", borderRadius: 6, padding: "5px 8px", cursor: "pointer", opacity: selected === name ? 1 : 0.65, fontFamily: "'Wix Madefor Display', sans-serif" }}><span style={{ opacity: 0.5, marginRight: 4 }}>{selected === name ? "●" : "○"}</span>{name}</button>))}</div>
